// // This module implements a combinational logic circuit that outputs X based on the values of the inputs A1, A2, and the negative logic input B1_N. The output X will be 1 if both A1 and A2 are low (0), 0 if A1 is high and A2 is low (0) or if A1 is low and A2 is high, and will take the complement of B1_N when both A1 and A2 are high.
module top_module(
    X   ,
    A1  ,
    A2  ,
    B1_N
);output X   ;
    input  A1  ;
    input  A2  ;
    input  B1_N;

    assign X = (A1 & A2) ? 1 :
               (A1 & !A2) ? 0 :
               (!A1 & A2) ? 0 :
               ~B1_N;

endmodule
